.header {
  height: 50px;
  background-color: #026aa7;
  color: white;
  line-height: 50px; /* Căn giữa text theo chiều dọc */
  padding: 0 10px;
}

.app-bar {
  height: 40px;
  background-color: #026aa7;
}
.board-bar {
  height: 60px;
  background-color: #0079bf;
}
.board-content {
  height: calc(100vh - 40px - 60px);
  background-color: #f4f5f7;
}

.board-content {
  height: calc(100vh - 100px);
  background-color: #f4f5f7;
  overflow-x: auto;
  white-space: nowrap; /* Ngăn các cột xuống dòng */
}

body { margin: 0; font-family: sans-serif; }
.screen {
  height: 100vh;
  display: flex;
  flex-direction: column;
}
.app-bar { height: 58px; background: #333; flex-shrink: 0; }
.board-bar { height: 60px; background: #555; flex-shrink: 0; }
.board-content {
  flex-grow: 1; /* Lấp đầy không gian còn lại */
  display: flex;
  overflow-x: auto;
  overflow-y: hidden;
}
.column {
  min-width: 272px;
  width: 272px;
  margin: 0 4px;
  background: #ebecf0;
  border-radius: 3px;
  padding: 8px;
}
